// Obtém os itens de entrada
const items = $input.all();

// Une todas as saídas em um array único
const allAvaliacoes = items.flatMap(item => {
  try {
    return JSON.parse(item.json.output);
  } catch (error) {
    console.error("Erro ao parsear saída do agente:", error);
    return [];
  }
});

// Garante que cada contexto seja um item individual
return allAvaliacoes.map(contexto => ({
  json: {
    contexto: contexto.contexto || "",
    link_noticia: contexto.link_noticia || null,
    status: contexto.status || "reprovada",
    nota: Number(contexto.nota) || 0,
    justificativa: contexto.justificativa || ""
  }
}));
